#!/usr/bin/env node
// scripts/refactor-campaign.mjs
//
// Refactor campaign — the measurable gate-delta formula (W2-T3, MASTER-PLAN §3A/§5).
//
// "Tech-debt sweep" was under-built as a vibe (operator flagged it). This script is the teeth:
// it reads plan/campaigns/refactor.yaml (repo selector + the five gate definitions: mutation UP,
// complexity DOWN, duplication DOWN, CVEs DOWN, fitness violations DOWN), computes each gate's
// CURRENT value from a fresh report (never a stale checked-in number — mutation/jscpd/depcruise/
// npm-audit reports are all regenerated by the CI job before this script runs; complexity is
// computed live, in-process, over src/**), compares against the recorded baseline, and renders
// either:
//
//   dry-run  — names the tech-debt targets (top-N files ranked by this script's own cyclomatic-
//              approximation complexity scan, cross-referenced against which of those files also
//              show up in the duplication/fitness reports) plus the project-wide gate deltas.
//              Read-only: makes no change, exits 0 always (a dry-run is advisory, never a gate).
//
//   check    — the CI gate. GREEN (exit 0) iff (a) no gate regressed versus its baseline and
//              (b) at least one gate strictly improved. A refactor that leaves every number
//              unchanged is a no-op, not a refactor — RED. A refactor that regresses one gate to
//              buy improvement on another is RED too (no trading one debt for another). Exits
//              non-zero (fail CLOSED) when a required current-value report is missing, same
//              convention as mutation-ratchet.mjs/coverage-ratchet.mjs — "can't prove it improved"
//              is treated the same as "didn't improve".
//
// Usage:
//   node scripts/refactor-campaign.mjs dry-run [--config <path>] [--repo-root <path>]
//     [--mutation-report <path>] [--jscpd-report <path>] [--depcruise-report <path>]
//     [--audit-report <path>] [--top-n <n>]
//   node scripts/refactor-campaign.mjs check [same flags]
//
// Defaults: --config plan/campaigns/refactor.yaml, --repo-root the current working directory,
// report paths from the config's own `source.path` per gate, --top-n from the config's
// `targets.top_n` (10 if the config omits it).
//
// The pure functions below (computeFileComplexity, scanComplexity, parseMutationScore,
// parseJscpdPercentage, parseDepcruiseViolations, parseAuditTotal, computeGateDelta,
// evaluateCampaign, rankTargets) are exported so the falsifier fixture test can exercise both the
// CLI process directly (spawn + exit code) and the parsing/comparison logic in isolation.

import { readFileSync, readdirSync, statSync } from 'node:fs';
import { join, relative, sep } from 'node:path';
import { parseArgs } from 'node:util';
import { pathToFileURL } from 'node:url';
import { parse as parseYaml } from 'yaml';

// ── Complexity scan (the one metric this script computes itself, not read from a tool report) ──

/**
 * Strip block comments, line comments, and string/template literal bodies before counting
 * decision points -- a heuristic, not a real parser, but it keeps prose inside JSDoc (this
 * codebase's comments routinely say "if", "case", "catch" in plain English) from inflating the
 * complexity score of a file that has none of that logic in actual code.
 * @param {string} src
 */
export function stripCommentsAndStrings(src) {
  return src
    .replace(/\/\*[\s\S]*?\*\//g, '')
    .replace(/\/\/.*$/gm, '')
    .replace(/`(?:\\.|[^`\\])*`/g, '``')
    .replace(/"(?:\\.|[^"\\])*"/g, '""')
    .replace(/'(?:\\.|[^'\\])*'/g, "''");
}

const DECISION_POINT_RE = /\b(if|for|while|case|catch)\b|&&|\|\||\?\?|\?(?!\?)/g;

/**
 * A cyclomatic-complexity APPROXIMATION for one file: 1 (baseline path) + one per decision point
 * (if/for/while/case/catch/&&/||/??/ternary `?`) found in the code after comments/strings are
 * stripped. This is a file-level MASS, not a per-function score -- good enough to RANK files by
 * how much branching logic they carry, which is exactly what a refactor campaign needs to name
 * targets, without adding a real AST-based complexity dependency to this project.
 * @param {string} source
 */
export function computeFileComplexity(source) {
  const code = stripCommentsAndStrings(source);
  const matches = code.match(DECISION_POINT_RE) ?? [];
  return 1 + matches.length;
}

/**
 * Recursively list `.ts` files under `dir` (relative to `dir`), excluding `.d.ts` declaration
 * files -- mirrors the jscpd/depcruise configs' own `src/**` scope.
 * @param {string} dir
 * @returns {string[]} paths relative to `dir`, POSIX-separated
 */
function listTsFiles(dir) {
  /** @type {string[]} */
  const out = [];
  /** @param {string} current */
  const walk = (current) => {
    for (const entry of readdirSync(current)) {
      const full = join(current, entry);
      const st = statSync(full);
      if (st.isDirectory()) {
        walk(full);
      } else if (entry.endsWith('.ts') && !entry.endsWith('.d.ts')) {
        out.push(relative(dir, full).split(sep).join('/'));
      }
    }
  };
  walk(dir);
  return out;
}

/**
 * Scan every `.ts` file under `srcDir` and return the aggregate complexity plus a per-file map --
 * the aggregate is the gate's CURRENT value (direction: down), the per-file map is what
 * {@link rankTargets} ranks the dry-run's named targets from.
 * @param {string} srcDir
 */
export function scanComplexity(srcDir) {
  /** @type {Record<string, number>} */
  const files = {};
  let totalComplexity = 0;
  for (const relPath of listTsFiles(srcDir)) {
    const source = readFileSync(join(srcDir, relPath), 'utf8');
    const score = computeFileComplexity(source);
    files[relPath] = score;
    totalComplexity += score;
  }
  return { totalComplexity, files };
}

// ── Current-value parsers for the four report-backed gates ──────────────

/** Mirrors scripts/mutation-ratchet.mjs's parseMutationTotals -- overall Stryker mutation score. */
export function parseMutationScore(report) {
  let killed = 0;
  let timeout = 0;
  let survived = 0;
  let noCoverage = 0;
  const files = report.files ?? {};
  for (const filePath of Object.keys(files)) {
    for (const mutant of files[filePath].mutants ?? []) {
      if (mutant.status === 'Killed') killed += 1;
      else if (mutant.status === 'Timeout') timeout += 1;
      else if (mutant.status === 'Survived') survived += 1;
      else if (mutant.status === 'NoCoverage') noCoverage += 1;
    }
  }
  const validTotal = killed + timeout + survived + noCoverage;
  return validTotal > 0 ? (100 * (killed + timeout)) / validTotal : 100;
}

/** jscpd's own JSON reporter shape: statistics.total.percentage is the overall duplicated-lines %. */
export function parseJscpdPercentage(report) {
  return report?.statistics?.total?.percentage ?? 0;
}

/** dependency-cruiser's `--output-type json`: summary.violations is the forbidden-rule hit list. */
export function parseDepcruiseViolations(report) {
  return report?.summary?.violations?.length ?? 0;
}

/** `npm audit --json`: metadata.vulnerabilities.total across every severity. */
export function parseAuditTotal(report) {
  return report?.metadata?.vulnerabilities?.total ?? 0;
}

// ── The gate-delta formula ────────────────────────────────────────────────

/**
 * Compare one gate's CURRENT value against its baseline. `improved`/`regressed` are judged
 * relative to `direction` ("up": higher is better; "down": lower is better); values within
 * `epsilon` of the baseline are `unchanged` -- never `improved` or `regressed` on floating-point
 * noise alone. `epsilon` defaults to `gate.epsilon` (a config-declared per-gate tolerance -- e.g.
 * the duplication gate's percentage carries real measurement noise from jscpd's own tokenizer
 * that a 1-2 line change produces even when nothing meaningful moved) and falls back to `1e-9`
 * (effectively exact-match) for gates that declare none, which is correct for the integer-valued
 * gates (complexity/cve/fitness) where there is no such noise.
 * @param {{id:string, label?:string, direction:'up'|'down', epsilon?:number}} gate
 * @param {number} baseline
 * @param {number} current
 * @param {number} [epsilon]
 */
export function computeGateDelta(gate, baseline, current, epsilon = gate.epsilon ?? 1e-9) {
  const delta = current - baseline;
  let verdict = 'unchanged';
  if (Math.abs(delta) > epsilon) {
    const better = gate.direction === 'up' ? delta > 0 : delta < 0;
    verdict = better ? 'improved' : 'regressed';
  }
  return { id: gate.id, label: gate.label ?? gate.id, direction: gate.direction, baseline, current, delta, verdict };
}

/**
 * The campaign-wide verdict: GREEN iff no gate regressed AND at least one gate improved. A
 * refactor that touches nothing measurable (every gate `unchanged`) is a no-op -- RED, matching
 * the acceptance criterion "a refactor PR that does not improve the gate numbers is CI-red". A
 * refactor that regresses even one gate is RED regardless of how much another gate improved (no
 * trading one debt for another).
 * @param {ReturnType<typeof computeGateDelta>[]} deltas
 */
export function evaluateCampaign(deltas) {
  const regressed = deltas.filter((d) => d.verdict === 'regressed');
  const improved = deltas.filter((d) => d.verdict === 'improved');
  const reasons = [];
  if (regressed.length > 0) {
    for (const d of regressed) {
      reasons.push(`${d.id} regressed: ${d.current} vs baseline ${d.baseline} (direction: ${d.direction})`);
    }
  } else if (improved.length === 0) {
    reasons.push('no gate improved -- every metric is unchanged versus its baseline (a no-op refactor)');
  }
  const verdict = regressed.length === 0 && improved.length > 0 ? 'green' : 'red';
  return { verdict, deltas, regressed, improved, reasons };
}

// ── Named tech-debt targets for the dry-run ──────────────────────────────

/**
 * Rank the top `topN` files by complexity (descending) and annotate each with the OTHER gates
 * that also flag it: a duplication hit (the file appears as either side of a jscpd clone pair)
 * or a fitness violation (the file appears in a depcruise violation's `from`/`to`).
 * @param {Record<string, number>} complexityFiles path (relative to srcDir, no `src/` prefix) -> score
 * @param {string} srcDir the directory the complexity scan ran over (used to reconstitute the
 *   `src/...` path jscpd/depcruise report against, since both tools are invoked with `src` as
 *   their target and so report paths relative to it too)
 * @param {number} topN
 * @param {{duplicates?: Array<{firstFile?:{name?:string}, secondFile?:{name?:string}}>}} [jscpdReport]
 * @param {{modules?: Array<{source?:string, dependencies?: Array<{resolved?:string, valid?:boolean, rules?: Array<{name?:string}>}>}>}} [depcruiseReport]
 */
export function rankTargets(complexityFiles, topN, jscpdReport, depcruiseReport) {
  const dupFiles = new Set();
  for (const dup of jscpdReport?.duplicates ?? []) {
    if (dup.firstFile?.name) dupFiles.add(dup.firstFile.name);
    if (dup.secondFile?.name) dupFiles.add(dup.secondFile.name);
  }
  const fitnessFiles = new Set();
  for (const mod of depcruiseReport?.modules ?? []) {
    for (const dep of mod.dependencies ?? []) {
      if ((dep.rules?.length ?? 0) > 0) {
        if (mod.source) fitnessFiles.add(mod.source);
        if (dep.resolved) fitnessFiles.add(dep.resolved);
      }
    }
  }

  return Object.entries(complexityFiles)
    .sort((a, b) => b[1] - a[1])
    .slice(0, topN)
    .map(([path, complexity]) => {
      const flags = [];
      if (dupFiles.has(path)) flags.push('duplication');
      if (fitnessFiles.has(`src/${path}`) || fitnessFiles.has(path)) flags.push('fitness');
      return { path: `src/${path}`, complexity, alsoFlaggedBy: flags };
    });
}

// ── Config loading + report gathering ────────────────────────────────────

function readJson(path) {
  return JSON.parse(readFileSync(path, 'utf8'));
}

/** @param {string} path */
export function loadCampaignConfig(path) {
  return parseYaml(readFileSync(path, 'utf8'));
}

function currentValueForGate(gate, opts) {
  switch (gate.source.kind) {
    case 'mutation-report':
      return parseMutationScore(readJson(opts.mutationReport ?? gate.source.path));
    case 'complexity-scan':
      return opts.complexityScan.totalComplexity;
    case 'jscpd-report':
      return parseJscpdPercentage(readJson(opts.jscpdReport ?? gate.source.path));
    case 'npm-audit-report':
      return parseAuditTotal(readJson(opts.auditReport ?? gate.source.path));
    case 'depcruise-report':
      return parseDepcruiseViolations(readJson(opts.depcruiseReport ?? gate.source.path));
    default:
      throw new Error(`refactor-campaign: unknown gate source kind '${gate.source.kind}'`);
  }
}

function baselineValueForGate(gate) {
  const baseline = readJson(gate.baseline);
  const value = baseline[gate.baseline_field];
  if (typeof value !== 'number') {
    throw new Error(`refactor-campaign: baseline '${gate.baseline}' has no numeric field '${gate.baseline_field}'`);
  }
  return value;
}

/**
 * Build every gate's {@link computeGateDelta} result for one campaign config. Throws (fail
 * CLOSED -- "can't prove it improved" is not "improved") when a report-backed gate's current
 * value can't be read, e.g. the CI job didn't generate that report.
 */
function buildDeltas(config, opts) {
  return config.gates.map((gate) => {
    const baseline = baselineValueForGate(gate);
    const current = currentValueForGate(gate, opts);
    return computeGateDelta(gate, baseline, current);
  });
}

// ── Rendering ──────────────────────────────────────────────────────────

function renderDryRun(config, deltas, targets) {
  const lines = [];
  lines.push(`refactor-campaign dry-run (${config.repo}) -- no change made, advisory only`);
  lines.push('');
  lines.push('project-wide gates (current vs baseline):');
  for (const d of deltas) {
    lines.push(
      `  - ${d.id} (${d.direction}-is-better): current=${round(d.current)} baseline=${round(d.baseline)} delta=${round(d.delta)} [${d.verdict}]`,
    );
  }
  lines.push('');
  lines.push(`named tech-debt targets (top ${targets.length} by complexity):`);
  if (targets.length === 0) {
    lines.push('  (none -- src/ scan found no .ts files)');
  }
  for (const t of targets) {
    const flags = t.alsoFlaggedBy.length > 0 ? ` [also flagged by: ${t.alsoFlaggedBy.join(', ')}]` : '';
    lines.push(`  - ${t.path}: complexity=${t.complexity}${flags}`);
  }
  return lines.join('\n');
}

function round(n) {
  return Math.round(n * 100) / 100;
}

function renderCheck(config, result) {
  const lines = [];
  lines.push(`refactor-campaign check (${config.repo}): ${result.verdict.toUpperCase()}`);
  for (const d of result.deltas) {
    lines.push(
      `  - ${d.id} (${d.direction}-is-better): current=${round(d.current)} baseline=${round(d.baseline)} delta=${round(d.delta)} [${d.verdict}]`,
    );
  }
  if (result.verdict === 'red') {
    lines.push('');
    lines.push('refactor-campaign: BLOCKED --');
    for (const r of result.reasons) lines.push(`  - ${r}`);
  }
  return lines.join('\n');
}

// ── CLI ────────────────────────────────────────────────────────────────

function main(argv) {
  const [mode, ...rest] = argv;
  if (mode !== 'dry-run' && mode !== 'check') {
    console.error(`refactor-campaign: unknown mode '${mode ?? ''}' -- expected 'dry-run' or 'check'`);
    process.exitCode = 1;
    return;
  }

  const { values } = parseArgs({
    args: rest,
    options: {
      config: { type: 'string', default: 'plan/campaigns/refactor.yaml' },
      'mutation-report': { type: 'string' },
      'jscpd-report': { type: 'string' },
      'depcruise-report': { type: 'string' },
      'audit-report': { type: 'string' },
      'top-n': { type: 'string' },
    },
  });

  const config = loadCampaignConfig(values.config);
  const complexityGate = config.gates.find((g) => g.source.kind === 'complexity-scan');
  const complexityScan = scanComplexity(complexityGate ? complexityGate.source.path : 'src');

  const opts = {
    mutationReport: values['mutation-report'],
    jscpdReport: values['jscpd-report'],
    depcruiseReport: values['depcruise-report'],
    auditReport: values['audit-report'],
    complexityScan,
  };

  let deltas;
  try {
    deltas = buildDeltas(config, opts);
  } catch (err) {
    console.error(`refactor-campaign: ${err instanceof Error ? err.message : String(err)}`);
    process.exitCode = 1;
    return;
  }

  if (mode === 'dry-run') {
    const topN = values['top-n'] ? Number(values['top-n']) : (config.targets?.top_n ?? 10);
    let jscpdReport;
    let depcruiseReport;
    try {
      const jscpdGate = config.gates.find((g) => g.source.kind === 'jscpd-report');
      jscpdReport = readJson(opts.jscpdReport ?? jscpdGate?.source.path);
    } catch {
      jscpdReport = undefined;
    }
    try {
      const depcruiseGate = config.gates.find((g) => g.source.kind === 'depcruise-report');
      depcruiseReport = readJson(opts.depcruiseReport ?? depcruiseGate?.source.path);
    } catch {
      depcruiseReport = undefined;
    }
    const targets = rankTargets(complexityScan.files, topN, jscpdReport, depcruiseReport);
    console.log(renderDryRun(config, deltas, targets));
    process.exitCode = 0;
    return;
  }

  // mode === 'check'
  const result = evaluateCampaign(deltas);
  console.log(renderCheck(config, result));
  process.exitCode = result.verdict === 'green' ? 0 : 1;
}

// Only run when executed directly (`node scripts/refactor-campaign.mjs ...`), never on import.
if (import.meta.url === pathToFileURL(process.argv[1] ?? '').href) {
  main(process.argv.slice(2));
}
